INSERT INTO `chatbot_documents` VALUES (9,'faq-shipping','faq','უფასო მიწოდება მთელი ქვეყნის მასშტაბით','მიწოდება უფასოა მთელი ქვეყნის მასშტაბით და ხდება შეკვეთის გაფორმებიდან მოკლე ვადაში.\\n\\nკურიერი წინასწარ დაგიკავშირდებათ და დაგიზუსტებთ მისამართს და მისვლის სავარაუდო დროს, რათა ზედმეტად არ მოგიწიოთ ლოდინი.',NULL,'{\"category\": \"მიწოდება\"}',NULL,1,'2026-02-22 16:44:28','2026-02-28 19:45:15'),(10,'faq-warranty','faq','გარანტია','ყველა ჩვენს სმარტსაათზე ვრცელდება ოფიციალური გარანტია, რომელიც მოიცავს წარმოების დეფექტებს და დანადგარის გაუმართაობას.\n\nგარანტიის ვადა და დეტალური პირობები მითითებულია თითოეული პროდუქტის აღწერაში. თუ საათი ნორმალური გამოყენებისას გაფუჭდა, დაუკავშირდით ჩვენს მომსახურების გუნდს და ერთად ვიპოვით საუკეთესო გადაწყვეტილებას.',NULL,'{\"category\": \"გარანტია და დაბრუნება\"}',NULL,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(11,'faq-returns','faq','დაბრუნება და შეცვლა','ნივთის დაბრუნება შესაძლებელია მიღებიდან 7 კალენდარული დღის განმავლობაში, თუ მას შენარჩუნებული აქვს სასაქონლო იერსახე და სრული შეფუთვა.\n\nდაბრუნების პროცესის დასაწყებად დაგვიკავშირდით ერთ-ერთ საკონტაქტო არხზე და ოპერატორი დეტალურად აგიხსნით შემდეგ ნაბიჯებს.',NULL,'{\"category\": \"გარანტია და დაბრუნება\"}',NULL,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(12,'faq-gps','faq','GPS ფუნქციები','GPS ფუნქცია საშუალებას გაძლევთ რეალურ დროში იხილოთ თქვენი ბავშვის მდებარეობა მობილურ აპლიკაციაში.\n\nაპლიკაციიდან შეგიძლიათ ნახოთ როგორც მიმდინარე ლოკაცია, ასევე გადაადგილების ისტორია. ზოგიერთი მოდელი მხარს უჭერს უსაფრთხო ზონების (გეოფენსის) დაყენებასაც — თუ ბავშვი ამ ზონას გასცდება, მიიღებთ შეტყობინებას.',NULL,'{\"category\": \"ბავშვის უსაფრთხოება\"}',NULL,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(13,'faq-sim','faq','SIM ბარათის მხარდაჭერა','სიმ ბარათი საჭიროა იმისთვის, რომ საათმა შეძლოს ზარების, შეტყობინებების და მონაცემების გაგზავნა/მიღება. რეკომენდებულია აქტიური SIM ბარათი ინტერნეტის პაკეტით, რათა GPS და ონლაინ ფუნქციები სტაბილურად იმუშაოს.\n\nSIM ბარათის ჩასმის ინსტრუქცია მითითებულია საათის სახელმძღვანელოში და საჭიროების შემთხვევაში შეგვიძლია ონლაინაც დაგეხმაროთ.',NULL,'{\"category\": \"პროდუქტის გამოყენება\"}',NULL,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(14,'faq-battery','faq','ბატარეის დრო','ბატარეის ხანგრძლივობა დამოკიდებულია გამოყენების ინტენსივობაზე. ჩვეულებრივ, ნორმალური დატვირთვისას საათი ერთ დამუხტვაზე 1-3 დღეს მუშაობს.\n\nთუ GPS მუდმივად ჩართულია და ბევრი ზარი მიმდინარეობს, ბატარეა უფრო სწრაფად დაიხარჯება – ასეთ შემთხვევაში რეკომენდებულია ყოველდღიური დამუხტვა.',NULL,'{\"category\": \"პროდუქტის გამოყენება\"}',NULL,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(15,'faq-water','faq','წყალგამძლეობა','ზოგი მოდელი წყლისადმი გამძლეა ყოველდღიური გამოყენებისთვის – ხელის დაბანისას ან მსუბუქი წვიმის დროს საათის მოხსნა საჭირო არ არის.\n\nპროდუქტის გვერდზე მითითებულია ზუსტი IP მაჩვენებელი, რომელიც განსაზღვრავს, რა დონემდეა საათი დაცული წყლისგან. გთხოვთ, არ გამოიყენოთ საათი ცურვის, ზღვის ან აუზის დროს, თუ ეს პირდაპირ არ არის ნებადართული მოდელის მახასიათებლებში.',NULL,'{\"category\": \"პროდუქტის გამოყენება\"}',NULL,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(16,'faq-app','faq','აპლიკაციის ინსტალაცია','საათის სრულფასოვანი გამოყენებისთვის საჭიროა მობილური აპლიკაციის დაყენება მშობლის ტელეფონზე.\n\nშეკვეთასთან ერთად მიიღებთ ინსტრუქციას ჩამოტვირთვის ბმულებით. აპლიკაციაში ბავშვის საათის მიბმა მარტივია და ნაბიჯ-ნაბიჯ ინსტრუქცია ხელმისაწვდომია ქართულ ენაზე.',NULL,'{\"category\": \"აპლიკაცია და მართვა\"}',NULL,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(17,'faq-payments','faq','გადახდის მეთოდები','გადახდა შესაძლებელია როგორც ნაღდი ანგარიშსწორებით კურიერთან, ასევე საბანკო გადარიცხვით.\n\nშეკვეთის გაფორმების შემდეგ ოპერატორი გამოგიგზავნით დეტალურ ინფორმაციას ანგარიშის ნომრისა და გადახდის დადასტურების წესის შესახებ.',NULL,'{\"category\": \"შეკვეთა და გადახდა\"}',NULL,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(18,'faq-contact','faq','დახმარება და კონტაქტი','თუ კითხვები დაგრჩათ, ყოველთვის შეგიძლიათ მოგვწეროთ Facebook-ზე, WhatsApp-ზე, Instagram-ზე, ელფოსტით ან დაგვირეკოთ.\n\nკონტაქტის გვერდზე ნახავთ ყველა საკონტაქტო არხს და სამუშაო საათებს. ვეცდებით, რომ შეტყობინებებს რაც შეიძლება სწრაფად ვუპასუხოთ.',NULL,'{\"category\": \"კონტაქტი\"}',NULL,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(21,'product-16','product','Wonlex KT34 — 4G საბავშვო სმარტ საათი GPS ტრეკერით','პროდუქტი: Wonlex KT34 — 4G საბავშვო სმარტ საათი GPS ტრეკერით\nslug: 2024-newest-style-4g-smart-watch-sos-call-wifi-lbs-gps-tracker-android-smart-watch-kid-sos-camera-alarm-clock-kt34\nფასი: 33.90 ლარი\nმოკლე აღწერა: Wonlex KT34 — 4G საბავშვო სმარტ საათი რეალურ დროში GPS მონიტორინგით, SOS ღილაკით, ხმოვანი და ვიდეო ზარებით. IP67 წყალგამძლეობა, გულისცემის სენსორი, ძილის მონიტორინგი. იმართება მობილური აპლიკაციით.\nაღწერა: Wonlex KT34 არის 4G საბავშვო სმარტ საათი, რომელიც მშობელს ბავშვის უსაფრთხოებაზე სრულ კონტროლს აძლევს.\r\n\r\nსაათი აღჭურვილია რეალურ დროში GPS ტრეკერით (GPS + WiFi + LBS), SOS საგანგებო ღილაკით, ხმოვანი და ვიდეო ზარის ფუნქციით. 1.85 ინჩიანი IPS სენსორული ეკრანი ნათელი და კარგად წაკითხვადია, ხოლო IP67 წყალგამძლეობის სტანდარტი საათს მტვრისა და წყლის შხეფებისგან იცავს.\r\n\r\nდამატებითი ფუნქციები: გულისცემის მონიტორი, ძილის ანალიზი, მაღვიძარა, კალენდარი და მშობლის დისტანციური მართვა აპლიკაციის საშუალებით. მხარს უჭერს Nano-SIM ბარათს. 1GB RAM + 8GB ROM მეხსიერება. კორპუსი რეზინის, სამაჯური — სილიკონის. ბატარეის ტევადობა უზრუნველყოფს 4 დღემდე მუშაობას ერთ დამუხტვაზე.\nSIM მხარდაჭერა: კი\nGPS ფუნქციები: კი\nწყალგამძლეობა: IP67\nბატარეა: 96 სთ\nოპერაციული სისტემა: RTOS\nეკრანის ზომა: 1.85 ინჩი\nდისპლეის ტიპი: IPS\nგაფართოება: 240*240\nბატარეის ტევადობა: 4 mAh\nკორპუსის მასალა: რეზინი\nსამაჯურის მასალა: სილიკონის გელი\nკამერა: < 3MP\nფუნქციები: GPS ტრეკერი (GPS + WiFi + LBS), SOS საგანგებო ღილაკი, ხმოვანი ზარი, ვიდეო ზარი, გულისცემის მონიტორი, ძილის მონიტორინგი, მაღვიძარა, კალენდარი, შეტყობინებები (Push), მშობლის დისტანციური მართვა, Wi-Fi, კამერა, სენსორული ეკრანი, 4G ქსელი\nვარიანტები:\n- შავი: მარაგშია (3 ცალი)\n- ლურჯი: მარაგშია (3 ცალი)\n- ვარდისფერი: მარაგშია (3 ცალი)\nსაერთო მარაგი: 9 ცალი',16,'{\"key\": \"product-16\", \"slug\": \"2024-newest-style-4g-smart-watch-sos-call-wifi-lbs-gps-tracker-android-smart-watch-kid-sos-camera-alarm-clock-kt34\", \"text\": \"პროდუქტი: Wonlex KT34 — 4G საბავშვო სმარტ საათი GPS ტრეკერით\\nslug: 2024-newest-style-4g-smart-watch-sos-call-wifi-lbs-gps-tracker-android-smart-watch-kid-sos-camera-alarm-clock-kt34\\nფასი: 33.90 ლარი\\nმოკლე აღწერა: Wonlex KT34 — 4G საბავშვო სმარტ საათი რეალურ დროში GPS მონიტორინგით, SOS ღილაკით, ხმოვანი და ვიდეო ზარებით. IP67 წყალგამძლეობა, გულისცემის სენსორი, ძილის მონიტორინგი. იმართება მობილური აპლიკაციით.\\nაღწერა: Wonlex KT34 არის 4G საბავშვო სმარტ საათი, რომელიც მშობელს ბავშვის უსაფრთხოებაზე სრულ კონტროლს აძლევს.\\r\\n\\r\\nსაათი აღჭურვილია რეალურ დროში GPS ტრეკერით (GPS + WiFi + LBS), SOS საგანგებო ღილაკით, ხმოვანი და ვიდეო ზარის ფუნქციით. 1.85 ინჩიანი IPS სენსორული ეკრანი ნათელი და კარგად წაკითხვადია, ხოლო IP67 წყალგამძლეობის სტანდარტი საათს მტვრისა და წყლის შხეფებისგან იცავს.\\r\\n\\r\\nდამატებითი ფუნქციები: გულისცემის მონიტორი, ძილის ანალიზი, მაღვიძარა, კალენდარი და მშობლის დისტანციური მართვა აპლიკაციის საშუალებით. მხარს უჭერს Nano-SIM ბარათს. 1GB RAM + 8GB ROM მეხსიერება. კორპუსი რეზინის, სამაჯური — სილიკონის. ბატარეის ტევადობა უზრუნველყოფს 4 დღემდე მუშაობას ერთ დამუხტვაზე.\\nSIM მხარდაჭერა: კი\\nGPS ფუნქციები: კი\\nწყალგამძლეობა: IP67\\nბატარეა: 96 სთ\\nოპერაციული სისტემა: RTOS\\nეკრანის ზომა: 1.85 ინჩი\\nდისპლეის ტიპი: IPS\\nგაფართოება: 240*240\\nბატარეის ტევადობა: 4 mAh\\nკორპუსის მასალა: რეზინი\\nსამაჯურის მასალა: სილიკონის გელი\\nკამერა: < 3MP\\nფუნქციები: GPS ტრეკერი (GPS + WiFi + LBS), SOS საგანგებო ღილაკი, ხმოვანი ზარი, ვიდეო ზარი, გულისცემის მონიტორი, ძილის მონიტორინგი, მაღვიძარა, კალენდარი, შეტყობინებები (Push), მშობლის დისტანციური მართვა, Wi-Fi, კამერა, სენსორული ეკრანი, 4G ქსელი\\nვარიანტები:\\n- შავი: მარაგშია (3 ცალი)\\n- ლურჯი: მარაგშია (3 ცალი)\\n- ვარდისფერი: მარაგშია (3 ცალი)\\nსაერთო მარაგი: 