--
-- Table structure for table `chatbot_test_results`
--

DROP TABLE IF EXISTS `chatbot_test_results`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `chatbot_test_results` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `test_run_id` bigint unsigned NOT NULL,
  `case_id` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `question` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `expected_summary` text COLLATE utf8mb4_unicode_ci,
  `actual_response` text COLLATE utf8mb4_unicode_ci,
  `rag_context` longtext COLLATE utf8mb4_unicode_ci,
  `intent_json` json DEFAULT NULL,
  `standalone_query` text COLLATE utf8mb4_unicode_ci,
  `intent_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `intent_confidence` decimal(6,4) DEFAULT NULL,
  `intent_latency_ms` int unsigned DEFAULT NULL,
  `status` enum('pass','fail','skip','error') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'skip',
  `keyword_match` tinyint(1) NOT NULL DEFAULT '0',
