INSERT INTO `chatbot_test_results` VALUES (1,1,'price-001','price_query','Garmin Venu 3 რა ღირს?','Keywords: ₾, ლარი','ზუსტი ფასი და მარაგი ამ მომენტში დამატებით გადამოწმებას საჭიროებს. გთხოვთ, დაგვიკავშირდეთ და დაუყოვნებლივ დაგიზუსტებთ ინფორმაციას.','Q21 — 2G წყალგამძლე საბავშვო სმარტ საათი\nპროდუქტი: Q21 — 2G წყალგამძლე საბავშვო სმარტ საათი\nslug: children-smartwatch\nფასი: 6.80 ლარი\nმოკლე აღწერა: Q21 — ხელმისაწვდომი 2G წყალგამძლე საბავშვო სმარტ საათი SOS ღილაკით, LBS მდებარეობის მონიტორინგით, ზარის ფუნქციით და ტელეფონის წიგნით. 1.44\" სენსორული ეკრანი.\nაღწერა: Q21 არის მარტივი და საიმედო 2G საბავშვო სმარტ საათი, რომელიც ბავშვის უსაფრთხოების ძირითად საჭიროებებს ფარავს.\r\n\r\nსაათს აქვს SOS საგანგებო ღილაკი, LBS მდებარეობის მონიტორინგი, ზარის განხორციელებისა და მიღების შესაძლებლობა, ტელეფონის წიგნი და კამერა. 1.44 ინჩიანი სენსორული ეკრანი მარტივი ინტერფეისით. წყალგამძლე კორპუსი ყოველდღიური გამოყენებისთვის.\r\n\r\n400mAh ბატარეა, სრულ დამუხტვას სჭირდება დაახლოებით 2 საათი. პლასტმასის კორპუსი, სილიკონის სამაჯური. იმართება მობილური აპლიკაციით. კარგი არჩევანია, როგორც ბავშვის პირველი სმარტ საათი.\nSIM მხარდაჭერა: კი\nGPS ფუნქციები: კი\nწყალგამძლეობა: წყალგაუმტარი\nბატარეა: 96 სთ\nოპერაციული სისტემა: 0.150 კგ\nეკრანის ზომა: 1.44\'\' სენსორული ეკრანი\nდისპლეის ტიპი: TFT\nგაფართოება: 128*128\nბატარეის ტევადობა: 400 mAh\nდამუხტვის დრო: 2.0 საათი\nკორპუსის მასალა: პლასტმასი\nსამაჯურის მასალა: სილიკონი\nფუნქციები: SOS საგანგებო ღილაკი, LBS მდებარეობა, ზარის განხორციელება, ტელეფონის წიგნი, კამერა, მშობლის დისტანციური მართვა, სენსორული ეკრანი, SIM ბარათი\nვარიანტები:\n- ვარდისფერი: მარაგშია (3 ცალი)\n- ლურჯი: მარაგშია (3 ცალი)\n- შავი: მარაგშია (3 ცალი)\nსაერთო მარაგი: 9 ცალი\nბმული: http://127.0.0.1:8000/products/children-smartwatch\n\nQ12 — 2G საბავშვო სმარტ საათი SOS ღილაკით\nპროდუქტი: Q12 — 2G საბავშვო სმარტ საათი SOS ღილაკით\nslug: high-quality-kids-smartwatch-q12-waterproof-ip67-2g-child-anti-lost-sos-call-gsm-lbs-location\nფასი: 4.18 ლარი\nმოკლე აღწერა: Q12 — ხელმისა