INSERT INTO `chatbot_test_results` VALUES (63,2,'stock-005','stock_availability','Amazfit GTR 4-ის შავი ფერი გაქვთ?','Stock: from_db | Keywords: მარაგ, ხელმისაწვდომ','ზუსტი ფასი და მარაგი ამ მომენტში დამატებით გადამოწმებას საჭიროებს. გთხოვთ, დაგვიკავშირდეთ და დაუყოვნებლივ დაგიზუსტებთ ინფორმაციას.','T53 — 4G საბავშვო სმარტ საათი ვიდეო ზარითა და GPS-ით\nპროდუქტი: T53 — 4G საბავშვო სმარტ საათი ვიდეო ზარითა და GPS-ით\nslug: yqt-4g-sos-smart-watch-for-kids-video-call-1-83-camera-oem-factory-gps-smartwatch-for-children\nფასი: 16.80 ლარი\nმოკლე აღწერა: T53 — 4G საბავშვო სმარტ საათი ვიდეო ზარით, GPS ტრეკერით (GPS + LBS + WiFi), SOS ღილაკით და თერმომეტრით. IP67 წყალგამძლეობა, 750mAh ბატარეა, LED ფანარი.\nაღწერა: T53 არის მრავალფუნქციური 4G საბავშვო სმარტ საათი, რომელიც უსაფრთხოებისა და კომუნიკაციის ფართო შესაძლებლობებს გვთავაზობს.\r\n\r\nსაათს აქვს GPS ტრეკერი (GPS + AGPS + LBS + WiFi) რეალურ დროში მდებარეობის მონიტორინგისთვის, SOS საგანგებო ღილაკი, ხმოვანი და ვიდეო ზარი. 1.83 ინჩიანი IPS სენსორული ეკრანი (320×240) ნათელი და ადვილად წაკითხვადია. IP67 წყალგამძლეობა საათს მტვრისა და წყლის შხეფებისგან იცავს.\r\n\r\nგამორჩეული ფუნქციები: ჩაშენებული თერმომეტრი, LED ფანარი, ძილის მონიტორინგი, მაღვიძარა და მუსიკის პლეერი. მხარს უჭერს Nano-SIM ბარათს. 750mAh ბატარეა. თავსებადია Setracker2/YQT SMART აპლიკაციასთან (Android და iOS). 128MB მეხსიერება. პლასტმასის კორპუსი, სილიკონის სამაჯური.\nSIM მხარდაჭერა: კი\nGPS ფუნქციები: კი\nწყალგამძლეობა: IP67\nგარანტია: 30 თვე\nოპერაციული სისტემა: Android, IOS\nეკრანის ზომა: 36-40მმ\nდისპლეის ტიპი: IPS\nგაფართოება: 320x240\nბატარეის ტევადობა: 750 mAh\nკორპუსის მასალა: პლასტმასი\nსამაჯურის მასალა: სილიკონის გელი\nკამერა: < 3MP\nფუნქციები: GPS ტრეკერი (GPS + AGPS + LBS + WiFi), SOS საგანგებო ღილაკი, ხმოვანი ზარი, ვიდეო ზარი, თერმომეტრი, LED ფანარი, ძილის მონიტორინგი, მაღვიძარა, კალენდარი, მუსიკის პლეერი, შეტყობინებები (Push), მშობლის დისტანციური მართვა, სენსორული ეკრანი, 4G / 3G ქსელი, Nano-SIM, კამერა\nვარიანტები:\n- ვარდისფერი: მარაგშია (3 ცალი)\