DROP TABLE IF EXISTS `competitor_products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `competitor_products` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `competitor_source_id` bigint unsigned NOT NULL,
  `external_product_id` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `product_url_hash` char(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `product_url` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `image_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `current_price` decimal(10,2) DEFAULT NULL,
  `old_price` decimal(10,2) DEFAULT NULL,
  `currency` varchar(3) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'GEL',
  `availability` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_in_stock` tinyint(1) DEFAULT NULL,
  `last_seen_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `competitor_products_source_url_hash_unique` (`competitor_source_id`,`product_url_hash`),
  KEY `cp_src_ext_idx` (`competitor_source_id`,`external_product_id`),
  KEY `cp_src_seen_idx` (`competitor_source_id`,`last_seen_at`),
  CONSTRAINT `competitor_products_competitor_source_id_foreign` FOREIGN KEY (`competitor_source_id`) REFERENCES `competitor_sources` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=54 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

