INSERT INTO `facebook_posts` VALUES (1,1,25,'🚀 ახალი შესაძლებლობები შენი პატარა გმირისთვის! 🚀\r\n\r\nგაიცანი YQT-ის A49 — 4G წყალგამძლე საბავშვო სმარტ საათი GPS ტრეკერით! ⌚👦👧\r\n\r\n💥 ფასი მხოლოდ 13.00 ₾!  \r\n💥 1.83\" IPS სენსორული ეკრანი – კომფორტული და ნათელი ხედი  \r\n💥 4G მხარდაჭერა Nano-SIM-ით – მყისიერი კავშირი  \r\n💥 GPS ტრეკერი – უსაფრთხოების სრული კონტროლი  \r\n💥 SOS ღილაკი და ზარის ფუნქცია – სწრაფი დახმარება საჭიროების დროს  \r\n💥 წყალგაუმტარი სტანდარტი – სულ თან, ნებისმიერ გარემოში  \r\n💥 750mAh ბატარეა, რომელიც ეყოფა 96 საათამდე  \r\n\r\nმიეცი შვილს თავისუფლება და შენ კონტროლი! 🎯 დატკბი მშვიდობით, მაშინ როცა შენი პატარა თამაშობს ან სწავლობს.\r\n\r\n📲 შეუკვეთე ახლავე და დაიცავი შენი ძვირფასი ადამიანი!  \r\n👉 https://mytechnic.ge\r\n\r\n#smartwatch #სმარტსაათი #საბავშვოსაათი #GPS #უსაფრთხოება',NULL,1,0,'417018998164571_122192148848523970',NULL,'published','შექმენი Facebook-ის მარკეტინგული პოსტი ქართულ ენაზე ამ პროდუქტისთვის.\r\n\r\nპროდუქტის ინფორმაცია:\r\nპროდუქტი: A49 — 4G საბავშვო სმარტ საათი GPS ტრეკერით\r\nფასი: 13.00 ₾\r\nაღწერა: A49 — 4G წყალგამძლე საბავშვო სმარტ საათი GPS ტრეკერით, SOS ღილაკით და ზარის ფუნქციით. 1.83\" IPS სენსორული ეკრანი, 750mAh ბატარეა, Nano-SIM მხარდაჭერა.\r\nბრენდი: YQT\r\nSIM ბარათის მხარდაჭერა: დიახ\r\nGPS: დიახ\r\nწყალგამძლე: წყალგაუმტარი სტანდარტი\r\nბატარეა: 96 საათი\r\nკამერა: 0.08 მეგაპიქსელი\r\n\r\nტონი: exciting\r\n\r\nმოთხოვნები:\r\n- პოსტი უნდა იყოს მიმზიდველი და გაყიდვაზე ორიენტირებული\r\n- დაამატე შესაბამისი emoji-ები\r\n- დაამატე 3-5 ჰეშთეგი (მაგ: #smartwatch #საათი)\r\n- მაქსიმუმ 250 სიტყვა\r\n- დაამატე call-to-action ლინკით: https://mytechnic.ge\r\n- ხაზი გაუსვი ფასს და მთავარ ფუნქციებს\r\n\r\nდააბრუნე მხოლოდ პოსტის ტექსტი, არანაირი დამატებითი ახსნა.',NULL,'2026-03-09 12:40:07','2026-03-09 11:55:15','2026-03-09 12:40:07'),(2,1,25,'🎉 ახალი A49 — 4G საბავშვო სმარტ საათი YQT ბრენდის უკვე ხელმისაწვდომია! 🎉\r\n\r\nდაეუფლეთ ბავშვების უსაფრთხოებას და კომფორტს ერთიანად! A49 არის წყალგამძლე, 1.83\" IPS სენსორული ეკრანით, 4G მხარდაჭერით, GPS ტრეკერით და SOS ღილაკით, რომელიც ნებისმიერ დროს დაგეხმარებათ თქვენი ბავშვის მოსმენაში და მის ადგილმდებარეობის კონტროლში! 📍📞\r\n\r\n✅ ვიდეო ზარი \r\n✅ Nano-SIM მხარდაჭერა  \r\n✅ ზარის ფუნქცია  \r\n✅ წყალგაუმტარი სტანდარტი  \r\n✅ კომპაქტური და მოსახერხებელი დიზაინი  \r\n\r\nთქვენი შვილები უსაფრთხოდ და კომუნიკაბელურად, თქვენ კი მშვიდად რაც მთავარია! \r\n\r\n📲 არ დაკარგოთ დრო – შეუკვეთეთ ახლავე და გამოიყენეთ ყველა ეს ინოვაციური ფუნქცია!  \r\n👉 https://mytechnic.ge  \r\n\r\n#smartwatch #საათი #ბავშვისუსაფრთხოება #GPSთრეკერი #ტექნოლოგია \r\n\r\nდააბალანსეთ სილამაზე, ტექნოლოგია და სამშვიდე  A49-თან ერთად! ✨','https://mytechnic.ge/storage/images/products/smart-watch-for-kids-gps-tracker/05.jpg',1,1,'417018998164571_122192159072523970','18115059598567090','published','შექმენი Facebook-ის მარკეტინგული პოსტი ქართულ ენაზე ამ პროდუქტისთვის.\r\n\r\nპროდუქტის ინფორმაცია:\r\nპროდუქტი: A49 — 4G საბავშვო სმარტ საათი GPS ტრეკერით\r\nფასი: 13.00 ₾\r\nაღწერა: A49 — 4G წყალგამძლე საბავშვო სმარტ საათი GPS ტრეკერით, SOS ღილაკით და ზარის ფუნქციით. 1.83\" IPS სენსორული ეკრანი, 750mAh ბატარეა, Nano-SIM მხარდაჭერა.\r\nბრენდი: YQT\r\nSIM ბარათის მხარდაჭერა: დიახ\r\nGPS: დიახ\r\nწყალგამძლე: წყალგაუმტარი სტანდარტი\r\nბატარეა: 96 საათი\r\nკამერა: 0.08 მეგაპიქსელი\r\n\r\nტონი: exciting\r\n\r\nმოთხოვნები:\r\n- პოსტი უნდა იყოს მიმზიდველი და გაყიდვაზე ორიენტირებული\r\n- დაამატე შესაბამისი emoji-ები\r\n- დაამატე 3-5 ჰეშთეგი (მაგ: #smartwatch #საათი)\r\n- მაქსიმუმ 250 სიტყვა\r\n- დაამატე call-to-action ლინკით: https://mytechnic.ge\r\n- ხაზი გაუსვი ფასს და მთავარ ფუნქციებს\r\n\r\nდააბრუნე მხოლოდ პოსტის ტექსტი, არანაირი დამატებითი ახსნა.',NULL,'2026-03-09 14:56:01','2026-03-09 14:41:00','2026-03-09 14:56:01');
