  `answer` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'სხვა',
  `sort_order` int unsigned NOT NULL DEFAULT '0',
