/*!40000 ALTER TABLE `faqs` DISABLE KEYS */;
INSERT INTO `faqs` VALUES (1,'მიწოდება თბილისში','თბილისში მიწოდება ხდება შეკვეთის გაფორმებიდან მომდევნო სამუშაო დღეს და არის სრულიად უფასო.\n\nკურიერი წინასწარ დაგიკავშირდებათ და დაგიზუსტებთ მისამართს და მისვლის სავარაუდო დროს, რათა ზედმეტად არ მოგიწიოთ ლოდინი.','მიწოდება',0,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(2,'გარანტია','ყველა ჩვენს სმარტსაათზე ვრცელდება ოფიციალური გარანტია, რომელიც მოიცავს წარმოების დეფექტებს და დანადგარის გაუმართაობას.\n\nგარანტიის ვადა და დეტალური პირობები მითითებულია თითოეული პროდუქტის აღწერაში. თუ საათი ნორმალური გამოყენებისას გაფუჭდა, დაუკავშირდით ჩვენს მომსახურების გუნდს და ერთად ვიპოვით საუკეთესო გადაწყვეტილებას.','გარანტია და დაბრუნება',1,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(3,'დაბრუნება და შეცვლა','ნივთის დაბრუნება შესაძლებელია მიღებიდან 7 კალენდარული დღის განმავლობაში, თუ მას შენარჩუნებული აქვს სასაქონლო იერსახე და სრული შეფუთვა.\n\nდაბრუნების პროცესის დასაწყებად დაგვიკავშირდით ერთ-ერთ საკონტაქტო არხზე და ოპერატორი დეტალურად აგიხსნით შემდეგ ნაბიჯებს.','გარანტია და დაბრუნება',2,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(4,'GPS ფუნქციები','GPS ფუნქცია საშუალებას გაძლევთ რეალურ დროში იხილოთ თქვენი ბავშვის მდებარეობა მობილურ აპლიკაციაში.\n\nაპლიკაციიდან შეგიძლიათ ნახოთ როგორც მიმდინარე ლოკაცია, ასევე გადაადგილების ისტორია. ზოგიერთი მოდელი მხარს უჭერს უსაფრთხო ზონების (გეოფენსის) დაყენებასაც — თუ ბავშვი ამ ზონას გასცდება, მიიღებთ შეტყობინებას.','ბავშვის უსაფრთხოება',3,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(5,'SIM ბარათის მხარდაჭერა','სიმ ბარათი საჭიროა იმისთვის, რომ საათმა შეძლოს ზარების, შეტყობინებების და მონაცემების გაგზავნა/მიღება. რეკომენდებულია აქტიური SIM ბარათი ინტერნეტის პაკეტით, რათა GPS და ონლაინ ფუნქციები სტაბილურად იმუშაოს.\n\nSIM ბარათის ჩასმის ინსტრუქცია მითითებულია საათის სახელმძღვანელოში და საჭიროების შემთხვევაში შეგვიძლია ონლაინაც დაგეხმაროთ.','პროდუქტის გამოყენება',4,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(6,'ბატარეის დრო','ბატარეის ხანგრძლივობა დამოკიდებულია გამოყენების ინტენსივობაზე. ჩვეულებრივ, ნორმალური დატვირთვისას საათი ერთ დამუხტვაზე 1-3 დღეს მუშაობს.\n\nთუ GPS მუდმივად ჩართულია და ბევრი ზარი მიმდინარეობს, ბატარეა უფრო სწრაფად დაიხარჯება – ასეთ შემთხვევაში რეკომენდებულია ყოველდღიური დამუხტვა.','პროდუქტის გამოყენება',5,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(7,'წყალგამძლეობა','ზოგი მოდელი წყლისადმი გამძლეა ყოველდღიური გამოყენებისთვის – ხელის დაბანისას ან მსუბუქი წვიმის დროს საათის მოხსნა საჭირო არ არის.\n\nპროდუქტის გვერდზე მითითებულია ზუსტი IP მაჩვენებელი, რომელიც განსაზღვრავს, რა დონემდეა საათი დაცული წყლისგან. გთხოვთ, არ გამოიყენოთ საათი ცურვის, ზღვის ან აუზის დროს, თუ ეს პირდაპირ არ არის ნებადართული მოდელის მახასიათებლებში.','პროდუქტის გამოყენება',6,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(8,'აპლიკაციის ინსტალაცია','საათის სრულფასოვანი გამოყენებისთვის საჭიროა მობილური აპლიკაციის დაყენება მშობლის ტელეფონზე.\n\nშეკვეთასთან ერთად მიიღებთ ინსტრუქციას ჩამოტვირთვის ბმულებით. აპლიკაციაში ბავშვის საათის მიბმა მარტივია და ნაბიჯ-ნაბიჯ ინსტრუქცია ხელმისაწვდომია ქართულ ენაზე.','აპლიკაცია და მართვა',7,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(9,'გადახდის მეთოდები','გადახდა შესაძლებელია როგორც ნაღდი ანგარიშსწორებით კურიერთან, ასევე საბანკო გადარიცხვით.\n\nშეკვეთის გაფორმების შემდეგ ოპერატორი გამოგიგზავნით დეტალურ ინფორმაციას ანგარიშის ნომრისა და გადახდის დადასტურების წესის შესახებ.','შეკვეთა და გადახდა',8,1,'2026-02-22 16:44:28','2026-02-22 16:44:28'),(10,'დახმარება და კონტაქტი','თუ კითხვები დაგრჩათ, ყოველთვის შეგიძლიათ მოგვწეროთ Facebook-ზე, WhatsApp-ზე, Instagram-ზე, ელფოსტით ან დაგვირეკოთ.\n\nკონტაქტის გვერდზე ნახავთ ყველა საკონტაქტო არხს და სამუშაო საათებს. ვეცდებით, რომ შეტყობინებებს რაც შეიძლება სწრაფად ვუპასუხოთ.','კონტაქტი',9,1,'2026-02-22 16:44:28','2026-02-22 16:44:28');
