DROP TABLE IF EXISTS `messages`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `messages` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `conversation_id` bigint unsigned NOT NULL,
  `customer_id` bigint unsigned NOT NULL,
  `sender_type` enum('customer','admin','bot') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sender_id` bigint unsigned NOT NULL COMMENT 'Admin user_id if sender_type=admin, customer_id if sender_type=customer',
  `sender_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `content` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `media_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `media_type` enum('image','video','file','audio') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `platform_message_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Platform identifier for idempotency',
  `metadata` json DEFAULT NULL COMMENT 'Platform-specific data (coordinates, products, etc)',
  `encrypted` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Whether message content is encrypted',
  `confidential` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Mark message as containing sensitive/confidential info',
  `read_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `messages_platform_message_id_unique` (`platform_message_id`),
  KEY `messages_customer_id_foreign` (`customer_id`),
  KEY `messages_conversation_id_created_at_index` (`conversation_id`,`created_at`),
  KEY `messages_sender_type_sender_id_index` (`sender_type`,`sender_id`),
  KEY `messages_sender_type_index` (`sender_type`),
  KEY `messages_sender_name_index` (`sender_name`),
  CONSTRAINT `messages_conversation_id_foreign` FOREIGN KEY (`conversation_id`) REFERENCES `conversations` (`id`) ON DELETE CASCADE,
  CONSTRAINT `messages_customer_id_foreign` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=312 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
