INSERT INTO `messages` VALUES (9,5,5,'customer',5,'Widget User (widget_q)','ჰი',NULL,NULL,'home_a6300fd5-70c6-4516-aaaa-f1b9a7f72f92',NULL,0,0,NULL,'2026-02-23 12:36:28','2026-02-23 12:36:28'),(10,5,5,'bot',0,'KidSIM Assistant','გამარჯობა! როგორ შემიძლია დაგეხმაროთ KidSIM საათებთან დაკავშირებით? თუ გაქვთ კითხვები ან გჭირდებათ პროდუქტის შესახებ ინფორმაცია, მზად ვარ დაგეხმაროთ.',NULL,NULL,'home_e51b68e8-75ac-42bb-840c-4ab268ef3aac',NULL,0,0,NULL,'2026-02-23 12:36:37','2026-02-23 12:36:37'),(11,5,5,'admin',1,'Admin One','ჰი',NULL,NULL,'admin_69a36898e0383',NULL,0,0,NULL,'2026-02-28 22:13:44','2026-02-28 22:13:44'),(12,6,6,'customer',6,'Widget User (widget_p)','hi',NULL,NULL,'home_6523c905-9b7d-4510-ab27-fe9c1e87991d',NULL,0,0,NULL,'2026-02-28 22:37:15','2026-02-28 22:37:15'),(13,6,6,'bot',0,'MyTechnic Assistant','გამარჯობა! როგორ შემიძლია დაგეხმაროთ დღეს? თუ ბავშვებისთვის ჭკვიან საათს ეძებთ ან სხვა კითხვები გაქვთ, მზად ვარ პასუხის გასაცემად.',NULL,NULL,'home_75448cfc-b7f5-47b0-b5b2-c17dc5b56308',NULL,0,0,NULL,'2026-02-28 22:37:22','2026-02-28 22:37:22'),(14,6,6,'customer',6,'Widget User (widget_p)','ki',NULL,NULL,'home_8f87804c-e629-466f-a377-365e11bf9682',NULL,0,0,NULL,'2026-02-28 22:37:55','2026-02-28 22:37:55'),(15,6,6,'bot',0,'MyTechnic Assistant','გამარჯობა! გთხოვთ, დააზუსტოთ თქვენი კითხვა ან მოთხოვნა, რომ დაგეხმაროთ. თუ სმარტ საათების ან სხვა პროდუქტის შესახებ გაქვთ შეკითხვა, მზად ვარ დეტალურად გიპასუხოთ.',NULL,NULL,'home_2fe8a147-ae26-4647-aebf-dbc4d3b5520a',NULL,0,0,NULL,'2026-02-28 22:37:59','2026-02-28 22:37:59'),(16,6,6,'customer',6,'Widget User (widget_p)','ok',NULL,NULL,'home_63a00993-b096-4847-8dfe-6b6dab65b3ea',NULL,0,0,NULL,'2026-02-28 22:40:48','2026-02-28 22:40:48'),(17,6,6,'bot',0,'MyTechnic Assistant','გამარჯობა! როგორ შემიძლია დაგეხმაროთ? თუ გსურთ, შემიძლია შემოგთავაზოთ ჩვენი საბავშვო ჭკვიანი საათების არჩევანი ან მოგაწოდოთ დამატებითი ინფორმაცია რომელიმე მოდელზე.',NULL,NULL,'home_a68f22ab-aa08-4cbc-904e-6e99bbcd4fbd',NULL,0,0,NULL,'2026-02-28 22:40:57','2026-02-28 22:40:57'),(18,6,6,'customer',6,'Widget User (widget_p)','kai',NULL,NULL,'home_b2d6d23f-ab13-4ef2-b84c-ec24f1f1d614',NULL,0,0,NULL,'2026-02-28 22:41:11','2026-02-28 22:41:11'),(19,6,6,'bot',0,'MyTechnic Assistant','გამარჯობა! გთხოვთ, უფრო კონკრეტულად მითხარით, რაში გჭირდებათ დახმარება? მზად ვარ დაგეხმაროთ სმარტ საათებთან ან სხვა საკითხებში.',NULL,NULL,'home_3f5233ec-00b5-48f2-bd2a-c41cae466999',NULL,0,0,NULL,'2026-02-28 22:41:16','2026-02-28 22:41:16'),(20,6,6,'customer',6,'Widget User (widget_p)','hai',NULL,NULL,'home_2df8cdce-3646-474b-bfbb-945c54cb157e',NULL,0,0,NULL,'2026-02-28 22:45:30','2026-02-28 22:45:30'),(21,6,6,'bot',0,'MyTechnic Assistant','გამარჯობა! როგორ შემიძლია დაგეხმაროთ? თუ გაქვთ კითხვა ჩვენი საბავშვო სმარტ საათების შესახებ ან სხვა საკითხი, სიამოვნებით გიპასუხებთ.',NULL,NULL,'home_83e82573-1c60-45b4-8624-e48d5a7fea93',NULL,0,0,NULL,'2026-02-28 22:45:34','2026-02-28 22:45:34'),(22,6,6,'customer',6,'Widget User (widget_p)','qwe',NULL,NULL,'home_4039e487-40b9-4ffd-974b-8f464750cdb6',NULL,0,0,NULL,'2026-02-28 22:45:55','2026-02-28 22:45:55'),(23,6,6,'bot',0,'MyTechnic Assistant','გამარჯობა! გთხოვთ, დამისვით თქვენი შეკითხვა ან მითხარით, როგორ შემიძლია დაგეხმაროთ. თუ გსურთ ინფორმაცია საბავშვო სმარტ საათებზე, სიამოვნებით მოგაწვდით დეტალებს.',NULL,NULL,'home_f2154d14-6414-4208-8423-501900207141',NULL,0,0,NULL,'2026-02-28 22:45:59','2026-02-28 22:45:59'),(24,6,6,'customer',6,'Widget User (widget_p)','notify',NULL,NULL,'home_973559c2-7846-4106-ad3c-11815e6bcac6',NULL,0,0,NULL,'2026-02-28 22:48:21','2026-02-28 22:48:21'),(25,6,6,'bot',0,'MyTechnic Assistant','გთხოვთ, დააზუსტოთ, რა სახის შეტყობინება გსურთ მიიღოთ? მაგალითად, პროდუქტის მარაგის შესახებ, ფასდაკლებების შესახებ თუ სხვა? მე მზად ვარ დაგეხმაროთ!',NULL,NULL,'home_b573f40f-9ded-455e-9036-623dfc6bd324',NULL,0,0,NULL,'2026-02-28 22:48:25','2026-02-28 22:48:25'),(26,6,6,'customer',6,'Widget User (widget_p)','ko',NULL,NULL,'home_377ad21d-be1f-44ff-a9f7-16109b87b180',NULL,0,0,NULL,'2026-02-2